```java
@DataJpaTest
class OrderRepositoryN1Test {
    @Autowired OrderRepository repo;
    @Autowired EntityManager em;
    @Autowired TestEntityManager testEm;

    @BeforeEach void seed() {
        User u = testEm.persistAndFlush(new User("Aisha", "aisha@test.com"));
        Restaurant r = testEm.persistAndFlush(new Restaurant("Biryani House"));
        testEm.persistAndFlush(new Order(u, r, "DELIVERED"));
        testEm.persistAndFlush(new Order(u, r, "PLACED"));
        testEm.clear();  // ← evict from first-level cache!
    }

    @Test
    void findAllWithDetails_exactlyOneQuery() {
        SessionFactory sf = em.getEntityManagerFactory()
            .unwrap(SessionFactory.class);
        sf.getStatistics().setStatisticsEnabled(true);
        sf.getStatistics().clear();

        List<Order> orders = repo.findAllWithDetails();

        // Accessing associations should NOT fire extra queries:
        orders.forEach(o -> {
            assertNotNull(o.getUser().getName());
            assertNotNull(o.getRestaurant().getName());
        });

        long queryCount = sf.getStatistics().getPreparedStatementCount();
        assertEquals(1, queryCount, "N+1 detected! Expected 1 query, got " + queryCount);
    }
}
```

